def get_safe_speed(): 
    raw = input("Enter motor speed (0-255): ").strip() 
    # Safe default 
    speed = 0 
    # Validate input 
    try: 
        candidate = int(raw) 
        if 0 <= candidate <= 255: 
            speed = candidate 
        else: 
            print("Unsafe speed -> using safe default (0)") 
    except ValueError: 
        print("Invalid input -> using safe default (0)") 
    return speed 
